GUID retval;
	OLECHAR *guid_string;

	if (zend_parse_parameters_none() == FAILURE) {
		RETURN_THROWS();
	}

	php_com_initialize();
	if (CoCreateGuid(&retval) == S_OK && StringFromCLSID(&retval, &guid_string) == S_OK) {
		RETVAL_STR(php_com_olestring_to_string(guid_string, CP_ACP));

		CoTaskMemFree(guid_string);
	} else {
		RETURN_FALSE;
	}
